#!/usr/bin/env node

/**
 * Merge Feature Catalogs
 *
 * Intelligently combines auto-generated catalog with manual PRD overrides.
 *
 * Strategy:
 * 1. Use auto-generated file lists (always current)
 * 2. Use manual descriptions/business context (human-curated)
 * 3. Merge validation criteria
 * 4. Preserve custom fields from manual PRD
 *
 * Run: npm run docs:merge
 */

import fs from 'fs';
import path from 'path';

// ============================================================================
// Configuration
// ============================================================================

const CONFIG = {
  rootDir: process.cwd(),

  inputs: {
    autoGenerated: 'docs/generated-feature-catalog.json',
    aiGenerated: 'docs/ai-generated-feature-catalog.json',
    manual: 'testsprite_tests/standard_prd.json'
  },

  output: 'docs/merged-feature-catalog.json',

  // Fields to prefer from manual vs auto
  preferManual: [
    'description',  // Manual descriptions are usually better
    'product_overview',
    'core_goals',
    'user_flow_summary',
    'validation_criteria',
    'business_value',
    'success_metrics'
  ],

  preferAuto: [
    'files',  // Auto-generated file lists are always current
    'stats',
    'tech_stack'
  ]
};

// ============================================================================
// Helper Functions
// ============================================================================

function loadJSON(filePath) {
  try {
    const fullPath = path.join(CONFIG.rootDir, filePath);
    return JSON.parse(fs.readFileSync(fullPath, 'utf-8'));
  } catch (error) {
    console.warn(`⚠️  Could not load ${filePath}: ${error.message}`);
    return null;
  }
}

function findFeatureByName(features, name) {
  if (!features) return null;
  return features.find(f => f.name === name);
}

function mergeFeature(autoFeature, manualFeature) {
  if (!autoFeature && !manualFeature) return null;
  if (!autoFeature) return manualFeature;
  if (!manualFeature) return autoFeature;

  // Merge strategy: Manual descriptions/context + Auto file lists
  return {
    name: autoFeature.name || manualFeature.name,

    // Prefer manual description if available and meaningful
    description: (manualFeature.description && manualFeature.description.length > 50)
      ? manualFeature.description
      : autoFeature.description,

    // Use manual capabilities if available, otherwise auto
    capabilities: manualFeature.capabilities || autoFeature.capabilities,

    // Always use auto-generated file list (most current)
    files: autoFeature.files || manualFeature.files || [],

    // Always use auto-generated stats
    stats: autoFeature.stats,

    // Preserve any custom fields from manual
    ...(manualFeature.business_value && { business_value: manualFeature.business_value }),
    ...(manualFeature.target_users && { target_users: manualFeature.target_users }),
    ...(manualFeature.success_metrics && { success_metrics: manualFeature.success_metrics }),
    ...(manualFeature.dependencies && { dependencies: manualFeature.dependencies }),

    // Add merge metadata
    meta: {
      source: {
        description: manualFeature.description ? 'manual' : 'auto',
        files: 'auto',
        stats: 'auto'
      },
      auto_file_count: autoFeature.files?.length || 0,
      manual_file_count: manualFeature.files?.length || 0,
      ...(autoFeature.meta && { auto_meta: autoFeature.meta })
    }
  };
}

// ============================================================================
// Main Merge Function
// ============================================================================

function mergeCatalogs() {
  console.log('🔀 Merging Feature Catalogs\n');

  // Load all inputs
  const autoGenerated = loadJSON(CONFIG.inputs.autoGenerated);
  const aiGenerated = loadJSON(CONFIG.inputs.aiGenerated);
  const manual = loadJSON(CONFIG.inputs.manual);

  // Use AI-generated if available, otherwise use basic auto-generated
  const autoSource = aiGenerated || autoGenerated;

  if (!autoSource) {
    console.error('❌ No auto-generated catalog found. Run npm run docs:generate first.');
    process.exit(1);
  }

  console.log('📂 Loaded inputs:');
  console.log(`  ${autoSource === aiGenerated ? '🤖 AI-enhanced' : '📝 Basic'} catalog: ${autoSource.features?.length || 0} features`);
  console.log(`  📖 Manual PRD: ${manual?.code_summary?.features?.length || 0} features\n`);

  // Build merged catalog
  const merged = {
    meta: {
      type: 'Merged Feature Catalog',
      description: 'Combines auto-generated file inventory with human-curated descriptions',
      generated_at: new Date().toISOString(),
      generated_by: 'scripts/merge-feature-catalogs.js',
      sources: {
        auto_catalog: autoSource === aiGenerated ? 'ai-generated' : 'basic-generated',
        manual_prd: manual ? 'testsprite_tests/standard_prd.json' : 'none',
        ai_model: autoSource.meta?.ai_model
      }
    },

    // Use manual product overview if available
    ...(manual?.product_overview && { product_overview: manual.product_overview }),
    ...(manual?.core_goals && { core_goals: manual.core_goals }),
    ...(manual?.user_flow_summary && { user_flow_summary: manual.user_flow_summary }),
    ...(manual?.validation_criteria && { validation_criteria: manual.validation_criteria }),

    // Use auto-generated stats (always current)
    stats: {
      ...autoSource.stats,
      features_merged: 0,
      features_auto_only: 0,
      features_manual_only: 0,
      total_features: 0
    },

    // Use auto-generated tech stack (always current)
    tech_stack: autoSource.tech_stack,

    features: []
  };

  // Merge features
  const autoFeatures = autoSource.features || [];
  const manualFeatures = manual?.code_summary?.features || [];

  // Get all unique feature names
  const allFeatureNames = new Set([
    ...autoFeatures.map(f => f.name),
    ...manualFeatures.map(f => f.name)
  ]);

  console.log('🔄 Merging features:');

  for (const featureName of allFeatureNames) {
    const autoFeature = findFeatureByName(autoFeatures, featureName);
    const manualFeature = findFeatureByName(manualFeatures, featureName);

    const mergedFeature = mergeFeature(autoFeature, manualFeature);

    if (mergedFeature) {
      merged.features.push(mergedFeature);

      // Track merge stats
      if (autoFeature && manualFeature) {
        merged.stats.features_merged++;
        console.log(`  ✓ ${featureName} (merged)`);
      } else if (autoFeature) {
        merged.stats.features_auto_only++;
        console.log(`  + ${featureName} (auto only)`);
      } else {
        merged.stats.features_manual_only++;
        console.log(`  ℹ ${featureName} (manual only)`);
      }
    }
  }

  merged.stats.total_features = merged.features.length;

  // Sort features by name
  merged.features.sort((a, b) => a.name.localeCompare(b.name));

  // Write output
  const outputPath = path.join(CONFIG.rootDir, CONFIG.output);
  fs.mkdirSync(path.dirname(outputPath), { recursive: true });
  fs.writeFileSync(outputPath, JSON.stringify(merged, null, 2));

  console.log('\n✅ Merge complete!');
  console.log(`\n📊 Statistics:`);
  console.log(`  Total features: ${merged.stats.total_features}`);
  console.log(`  Merged (auto + manual): ${merged.stats.features_merged}`);
  console.log(`  Auto-only: ${merged.stats.features_auto_only}`);
  console.log(`  Manual-only: ${merged.stats.features_manual_only}`);
  console.log(`  Tech stack items: ${merged.tech_stack.length}`);
  console.log(`  Routes: ${merged.stats.routes.total}`);
  console.log(`\n💾 Output: ${CONFIG.output}`);

  // Generate summary report
  generateReport(merged);
}

// ============================================================================
// Generate Summary Report
// ============================================================================

function generateReport(catalog) {
  const reportPath = path.join(CONFIG.rootDir, 'docs/CATALOG_SUMMARY.md');

  const report = `# Feature Catalog Summary

*Auto-generated on ${new Date().toISOString()}*

## Overview

${catalog.product_overview || 'No product overview available.'}

## Statistics

- **Total Features**: ${catalog.stats.total_features}
- **Total Routes**: ${catalog.stats.routes.total}
  - Admin: ${catalog.stats.routes.admin}
  - Family: ${catalog.stats.routes.family}
  - Instructor: ${catalog.stats.routes.instructor}
  - API: ${catalog.stats.routes.api}
  - Public: ${catalog.stats.routes.public}
- **Tech Stack**: ${catalog.tech_stack.length} technologies

## Features

${catalog.features.map(feature => `
### ${feature.name}

${feature.description}

**Files**: ${feature.stats?.total || feature.files?.length || 0}
${feature.stats ? `
- Routes: ${feature.stats.routes}
- Services: ${feature.stats.services}
- Components: ${feature.stats.components}
- Utils: ${feature.stats.utils}` : ''}

${feature.capabilities ? `**Key Capabilities**:
${feature.capabilities.map(cap => `- ${cap}`).join('\n')}` : ''}
`).join('\n---\n')}

## Tech Stack

${catalog.tech_stack.map(tech => `- ${tech}`).join('\n')}

${catalog.validation_criteria ? `
## Validation Criteria

${catalog.validation_criteria.map((criteria, i) => `${i + 1}. ${criteria}`).join('\n')}
` : ''}

---

*This document is auto-generated. To update:*
\`\`\`bash
npm run docs:generate   # Generate base catalog
npm run docs:merge      # Merge with manual PRD
\`\`\`
`;

  fs.writeFileSync(reportPath, report);
  console.log(`📄 Summary report: docs/CATALOG_SUMMARY.md`);
}

// ============================================================================
// Run
// ============================================================================

mergeCatalogs();
